if "fastapi" not in sys.modules:
    fastapi_module = types.ModuleType("fastapi")

    class _FakeFastAPI:
        def __init__(self, *args, **kwargs):
            pass

        def add_middleware(self, *args, **kwargs):
            return None

        def _route(self, *args, **kwargs):
            def decorator(fn):
                return fn

            return decorator

        get = _route
        post = _route
        put = _route
        delete = _route
        patch = _route

    class _FakeHTTPException(Exception):
        def __init__(self, status_code: int = 500, detail: str = ""):
            super().__init__(detail)
            self.status_code = status_code
            self.detail = detail

    def _fake_body(default=None, **kwargs):
        return default

    class _FakeRequest:
        pass

    fastapi_module.FastAPI = _FakeFastAPI
    fastapi_module.HTTPException = _FakeHTTPException
    fastapi_module.Body = _fake_body
    fastapi_module.Request = _FakeRequest
    sys.modules["fastapi"] = fastapi_module

    fastapi_middleware = types.ModuleType("fastapi.middleware")
    fastapi_cors = types.ModuleType("fastapi.middleware.cors")

    class _FakeCorsMiddleware:
        pass

    fastapi_cors.CORSMiddleware = _FakeCorsMiddleware
    sys.modules["fastapi.middleware"] = fastapi_middleware
    sys.modules["fastapi.middleware.cors"] = fastapi_cors

