    def test_list_runbook_export_items_frontend_hint_hit_rate_and_precheck_completion_ratio(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))

        payload_old_blocked_unresolved = {
            "run_date": "2026-02-19",
            "alerts": ["frontend_hard_fail_apply_blocked"],
            "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
            "steps": [
                {
                    "id": "RB01",
                    "token": "precheck_frontend_hard_fail_apply_route_and_approval_manifest",
                    "gate": "frontend_hard_fail_apply_route_verified",
                    "cli_command": "frontend-hard-fail-approval-manifest",
                    "command_validation": {"degraded": True},
                }
            ],
        }
        payload_mid_no_hint = {
            "run_date": "2026-02-20",
            "alerts": ["workflow_store_strict_mode_violation"],
            "alert_details": [{"code": "workflow_store_strict_mode_violation", "severity": "critical"}],
            "steps": [],
        }
        payload_new_blocked_resolved = {
            "run_date": "2026-02-21",
            "alerts": ["frontend_hard_fail_apply_blocked"],
            "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
            "steps": [
                {
                    "id": "RB01",
                    "token": "precheck_frontend_hard_fail_apply_route_and_approval_manifest",
                    "gate": "frontend_hard_fail_apply_route_verified",
                    "cli_command": "frontend-hard-fail-approval-manifest",
                    "command_validation": {"degraded": False},
                }
            ],
        }

        (td / "2026-02-19_dashboard_runbook.json").write_text(
            json.dumps(payload_old_blocked_unresolved, ensure_ascii=False),
            encoding="utf-8",
        )
        (td / "2026-02-20_dashboard_runbook.json").write_text(
            json.dumps(payload_mid_no_hint, ensure_ascii=False),
            encoding="utf-8",
        )
        (td / "2026-02-21_dashboard_runbook.json").write_text(
            json.dumps(payload_new_blocked_resolved, ensure_ascii=False),
            encoding="utf-8",
        )

        with patch("dashboard.api.main.REVIEW_DIR", str(td)):
            items = list_runbook_export_items(limit=10)

        self.assertEqual(len(items), 3)
        latest = items[0] if isinstance(items[0], dict) else {}
        middle = items[1] if isinstance(items[1], dict) else {}
        oldest = items[2] if isinstance(items[2], dict) else {}

        self.assertTrue(bool(latest.get("frontend_hard_fail_apply_blocked_hint_hit", False)))
        self.assertTrue(bool(latest.get("frontend_hard_fail_apply_precheck_completed", False)))
        self.assertAlmostEqual(float(latest.get("frontend_hard_fail_apply_blocked_hint_hit_rate", -1.0)), 1.0, places=6)
        self.assertAlmostEqual(float(latest.get("frontend_hard_fail_apply_precheck_completion_ratio", -1.0)), 1.0, places=6)

        self.assertFalse(bool(middle.get("frontend_hard_fail_apply_blocked_hint_hit", True)))
        self.assertAlmostEqual(float(middle.get("frontend_hard_fail_apply_blocked_hint_hit_rate", -1.0)), 0.5, places=6)
        self.assertAlmostEqual(float(middle.get("frontend_hard_fail_apply_precheck_completion_ratio", -1.0)), 1.0, places=6)

        self.assertTrue(bool(oldest.get("frontend_hard_fail_apply_blocked_hint_hit", False)))
        self.assertFalse(bool(oldest.get("frontend_hard_fail_apply_precheck_completed", True)))
        self.assertAlmostEqual(float(oldest.get("frontend_hard_fail_apply_blocked_hint_hit_rate", -1.0)), 2.0 / 3.0, places=6)
        self.assertAlmostEqual(float(oldest.get("frontend_hard_fail_apply_precheck_completion_ratio", -1.0)), 0.5, places=6)

