    def test_build_route_audit_breach_timeline_compact_7d(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        (td / "2026-02-18_dashboard_runbook.json").write_text(
            json.dumps(
                {
                    "run_date": "2026-02-18",
                    "alerts": [],
                    "steps": [],
                    "cards": {"frontend_hard_fail_apply": {"route_audit_ok": True, "route_audit_status": "green"}},
                },
                ensure_ascii=False,
            ),
            encoding="utf-8",
        )
        (td / "2026-02-20_dashboard_runbook.json").write_text(
            json.dumps(
                {
                    "run_date": "2026-02-20",
                    "alerts": [],
                    "steps": [],
                    "cards": {
                        "frontend_hard_fail_apply": {
                            "route_audit_ok": True,
                            "route_audit_status": "yellow",
                            "route_audit_non_apply_ratio": 0.58,
                            "route_audit_apply_ratio": 0.21,
                            "route_audit_rollback_guard_ratio": 0.21,
                        }
                    },
                },
                ensure_ascii=False,
            ),
            encoding="utf-8",
        )
        (td / "2026-02-21_dashboard_runbook.json").write_text(
            json.dumps(
                {
                    "run_date": "2026-02-21",
                    "alerts": ["frontend_hard_fail_apply_blocked"],
                    "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
                    "steps": [],
                    "cards": {
                        "frontend_hard_fail_apply": {
                            "route_audit_ok": False,
                            "route_audit_status": "red",
                            "route_audit_non_apply_ratio": 0.81,
                            "route_audit_apply_ratio": 0.08,
                            "route_audit_rollback_guard_ratio": 0.11,
                        }
                    },
                },
                ensure_ascii=False,
            ),
            encoding="utf-8",
        )
        with patch("dashboard.api.main.REVIEW_DIR", str(td)):
            timeline = build_route_audit_breach_timeline(days=7)
        self.assertEqual(int(timeline.get("days", 0)), 7)
        self.assertEqual(str(timeline.get("anchor_run_date", "")), "2026-02-21")
        self.assertEqual(int(timeline.get("covered_days", 0)), 3)
        self.assertEqual(int(timeline.get("breached_days", 0)), 1)
        points = timeline.get("points", []) if isinstance(timeline.get("points", []), list) else []
        self.assertEqual(len(points), 7)
        by_day = {
            str((row or {}).get("run_date", "")): row
            for row in points
            if isinstance(row, dict)
        }
        p21 = by_day.get("2026-02-21", {})
        self.assertTrue(bool(p21.get("has_data", False)))
        self.assertTrue(bool(p21.get("breached", False)))
        self.assertEqual(str(p21.get("severity", "")), "high")
        self.assertEqual(str(p21.get("route_audit_status", "")), "red")
        self.assertEqual(str(p21.get("breach_transition", "")), "breach_entered")
        tags21 = p21.get("anomaly_tags", []) if isinstance(p21.get("anomaly_tags", []), list) else []
        self.assertIn("breach_entered", [str(x) for x in tags21])
        self.assertIn("non_apply_rise", [str(x) for x in tags21])
        p20 = by_day.get("2026-02-20", {})
        self.assertTrue(bool(p20.get("has_data", False)))
        self.assertFalse(bool(p20.get("breached", True)))
        self.assertEqual(str(p20.get("severity", "")), "medium")
        self.assertEqual(str(p20.get("breach_transition", "")), "stable_ok")
        p19 = by_day.get("2026-02-19", {})
        self.assertFalse(bool(p19.get("has_data", True)))
        self.assertEqual(str(p19.get("severity", "")), "none")
        self.assertEqual(str(p19.get("breach_transition", "")), "data_gap")
        tags19 = p19.get("anomaly_tags", []) if isinstance(p19.get("anomaly_tags", []), list) else []
        self.assertIn("data_gap", [str(x) for x in tags19])

    def test_build_route_audit_hint_calibration_bundle_uses_memo_cache(self) -> None:
        source_runs = [
            {
                "run_date": "2026-02-21",
                "modified_at": "2026-02-21T20:30:00Z",
                "risk_score": 7,
                "frontend_hard_fail_route_audit_status": "red",
                "triage_drift_status": "warn",
            }
        ]
        clear_route_audit_hint_calibration_cache()
        self.addCleanup(clear_route_audit_hint_calibration_cache)

        def _fake_timeline(days: int = 7, **kwargs):
            return {
                "days": int(days),
                "anchor_run_date": "2026-02-21",
                "covered_days": 1,
                "breached_days": 0,
                "points": [],
            }

        with patch(
            "dashboard.api.main.ROUTE_AUDIT_HINT_CALIBRATION_CACHE_TTL_SECONDS",
            600,
        ), patch(
            "dashboard.api.main.build_route_audit_breach_timeline",
            side_effect=_fake_timeline,
        ) as timeline_mock, patch(
            "dashboard.api.main.build_route_audit_hint_calibration_gap_trendline",
            return_value={"history_days": 30, "points": []},
        ) as trendline_mock:
            first = build_route_audit_hint_calibration_bundle(
                source_runs=source_runs,
                source_window_days=90,
                history_days=30,
                use_cache=True,
            )
            second = build_route_audit_hint_calibration_bundle(
                source_runs=source_runs,
                source_window_days=90,
                history_days=30,
                use_cache=True,
            )

        self.assertEqual(timeline_mock.call_count, 3)
        self.assertEqual(trendline_mock.call_count, 1)
        self.assertEqual(int(first.get("history_days", 0)), 30)
        self.assertEqual(int(second.get("history_days", 0)), 30)
        first_cache = first.get("_cache", {}) if isinstance(first.get("_cache", {}), dict) else {}
        second_cache = second.get("_cache", {}) if isinstance(second.get("_cache", {}), dict) else {}
        self.assertFalse(bool(first_cache.get("hit", True)))
        self.assertTrue(bool(second_cache.get("hit", False)))
        self.assertGreaterEqual(int(second_cache.get("hits", 0) or 0), 1)
        self.assertGreaterEqual(int(second_cache.get("misses", 0) or 0), 1)
        second_history = second_cache.get("history", []) if isinstance(second_cache.get("history", []), list) else []
        self.assertGreaterEqual(len(second_history), 2)
        last_point = second_history[-1] if isinstance(second_history[-1], dict) else {}
        self.assertTrue(bool(last_point.get("hit", False)))

