    def test_list_dashboard_review_runbook_exports_public_redacts_triage_actions(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        (td / "2026-02-21_dashboard_runbook.json").write_text(
            json.dumps(
                {
                    "run_date": "2026-02-21",
                    "alerts": ["frontend_hard_fail_apply_blocked"],
                    "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
                    "steps": [],
                },
                ensure_ascii=False,
            ),
            encoding="utf-8",
        )
        (td / "2026-02-21_gate_report.json").write_text("{}", encoding="utf-8")
        with patch("dashboard.api.main.REVIEW_DIR", str(td)):
            payload = list_dashboard_review_runbook_exports(
                request=None,
                limit=5,
                visibility=VISIBILITY_PUBLIC,
            )
        data = payload.get("data", {}) if isinstance(payload.get("data", {}), dict) else {}
        trend_triage = (
            data.get("route_audit_hint_gap_trend_triage_effectiveness", {})
            if isinstance(data.get("route_audit_hint_gap_trend_triage_effectiveness", {}), dict)
            else {}
        )
        self.assertIn("triggered_runs", trend_triage)
        self.assertIn("review_step_coverage", trend_triage)
        timeline = (
            data.get("route_audit_timeline_7d", {})
            if isinstance(data.get("route_audit_timeline_7d", {}), dict)
            else {}
        )
        self.assertEqual(int(timeline.get("days", 0)), 7)
        calibration = (
            data.get("route_audit_hint_calibration", {})
            if isinstance(data.get("route_audit_hint_calibration", {}), dict)
            else {}
        )
        self.assertTrue(isinstance(calibration.get("window_7d", {}), dict))
        self.assertTrue(isinstance(calibration.get("window_90d", {}), dict))
        for monitor_key in ("gap_monitor", "gap_monitor_7v30", "gap_monitor_30v90"):
            gap_monitor = (
                calibration.get(monitor_key, {})
                if isinstance(calibration.get(monitor_key, {}), dict)
                else {}
            )
            self.assertIn(str(gap_monitor.get("status", "")), {"inactive", "ok", "warn", "fail"})
            self.assertNotIn("bucket_gaps", gap_monitor)
            self.assertNotIn("recommended_command", gap_monitor)
        trendline = (
            calibration.get("trendline", {})
            if isinstance(calibration.get("trendline", {}), dict)
            else {}
        )
        self.assertTrue(isinstance(trendline.get("points", []), list))
        artifacts = calibration.get("artifacts", {}) if isinstance(calibration.get("artifacts", {}), dict) else {}
        art7 = artifacts.get("calibration_7d", {}) if isinstance(artifacts.get("calibration_7d", {}), dict) else {}
        art90 = artifacts.get("calibration_90d", {}) if isinstance(artifacts.get("calibration_90d", {}), dict) else {}
        self.assertEqual(str(art7.get("json_path", "")), "")
        self.assertEqual(str(art90.get("json_path", "")), "")
        items = data.get("items", []) if isinstance(data.get("items", []), list) else []
        self.assertEqual(len(items), 1)
        row = items[0] if isinstance(items[0], dict) else {}
        triage = row.get("triage_actions", {})
        self.assertEqual(triage, {})
        triage_playbook = row.get("triage_playbook", {})
        self.assertEqual(triage_playbook, {})
        self.assertIn("risk_score", row)
        self.assertIn("route_audit_hint_gap_trend_triage_effectiveness_drift_bucket", row)
        self.assertIn("route_audit_hint_gap_trend_triage_effectiveness_drift_score", row)
        self.assertIn("route_audit_hint_calibration_cache_status", row)
        self.assertIn("route_audit_hint_calibration_cache_hit_ratio_delta", row)
        self.assertTrue(isinstance(row.get("risk_score", 0), (int, float)))
        self.assertIn(
            str(row.get("route_audit_hint_gap_trend_triage_effectiveness_drift_bucket", "")).lower(),
            {"high", "warn", "low", "none"},
        )
        self.assertIn(
            str(row.get("route_audit_hint_calibration_cache_status", "")).lower(),
            {"fail", "warn", "ok", "inactive"},
        )
        artifacts = row.get("artifacts", {}) if isinstance(row.get("artifacts", {}), dict) else {}
        self.assertEqual(str(artifacts.get("gate_report_path", "")), "")

