    def test_list_dashboard_review_runbook_exports_latest_trigger_moves_when_window_topn_drop_triggered_rows(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        fixtures = [
            {
                "run_date": "2026-02-21",
                "defective": True,
                "alerts": ["frontend_hard_fail_apply_blocked"],
                "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
                "steps": [],
                "cards": {
                    "dependency_audit_artifact_trend": {
                        "status": "stale",
                        "gate_ok": False,
                        "alerts": ["dependency_audit_artifact_trend_stale"],
                    }
                },
            },
            {
                "run_date": "2026-02-22",
                "defective": True,
                "alerts": ["frontend_hard_fail_apply_blocked"],
                "alert_details": [{"code": "frontend_hard_fail_apply_blocked", "severity": "critical"}],
                "steps": [],
                "cards": {
                    "dependency_audit_artifact_trend": {
                        "status": "unknown",
                        "gate_ok": True,
                        "checks": {
                            "artifact_recent_ok": True,
                            "corrupt_ratio_ok": True,
                            "missing_ratio_ok": True,
                            "min_samples_ok": True,
                        },
                        "alerts": [],
                    }
                },
            },
            {
                "run_date": "2026-02-23",
                "defective": False,
                "alerts": [],
                "steps": [],
                "cards": {
                    "dependency_audit_artifact_trend": {
                        "status": "stale",
                        "gate_ok": False,
                        "alerts": ["dependency_audit_artifact_trend_stale"],
                    }
                },
            },
        ]
        for payload in fixtures:
            run_date = str(payload.get("run_date", ""))
            (td / f"{run_date}_dashboard_runbook.json").write_text(
                json.dumps(payload, ensure_ascii=False),
                encoding="utf-8",
            )

        def _rollup(payload: dict) -> tuple[dict, dict]:
            data = payload.get("data", {}) if isinstance(payload.get("data", {}), dict) else {}
            rollup = (
                data.get("dependency_trend_quick_action_rollup", {})
                if isinstance(data.get("dependency_trend_quick_action_rollup", {}), dict)
                else {}
            )
            return data, rollup

        with patch("dashboard.api.main.REVIEW_DIR", str(td)):
            baseline = list_dashboard_review_runbook_exports(
                request=None,
                limit=20,
                window_days=0,
                high_risk_top_n=0,
                visibility=VISIBILITY_PUBLIC,
            )
            filtered_topn = list_dashboard_review_runbook_exports(
                request=None,
                limit=20,
                window_days=0,
                high_risk_top_n=2,
                visibility=VISIBILITY_PUBLIC,
            )
            filtered_window_topn = list_dashboard_review_runbook_exports(
                request=None,
                limit=20,
                window_days=2,
                high_risk_top_n=1,
                visibility=VISIBILITY_PUBLIC,
            )

        baseline_data, baseline_rollup = _rollup(baseline)
        self.assertEqual(int(baseline_data.get("count", 0)), 3)
        self.assertEqual(int(baseline_rollup.get("triggered_runs", 0)), 2)
        self.assertEqual(str(baseline_rollup.get("latest_trigger_run_date", "")), "2026-02-23")
        self.assertEqual(str(baseline_rollup.get("latest_trigger_state", "")), "stale")

        filtered_topn_data, filtered_topn_rollup = _rollup(filtered_topn)
        self.assertEqual(int(filtered_topn_data.get("count", 0)), 2)
        self.assertEqual(int(filtered_topn_rollup.get("triggered_runs", 0)), 1)
        self.assertEqual(str(filtered_topn_rollup.get("latest_trigger_run_date", "")), "2026-02-21")
        self.assertEqual(str(filtered_topn_rollup.get("latest_trigger_state", "")), "stale")

        filtered_window_data, filtered_window_rollup = _rollup(filtered_window_topn)
        self.assertEqual(int(filtered_window_data.get("count", 0)), 1)
        self.assertEqual(int(filtered_window_rollup.get("triggered_runs", 0)), 0)
        self.assertEqual(str(filtered_window_rollup.get("latest_trigger_run_date", "")), "")
        self.assertEqual(str(filtered_window_rollup.get("latest_trigger_state", "")), "")

