    def test_list_dashboard_review_runbook_exports_equal_risk_topn_tie_uses_deterministic_fallback(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        file_a = td / "2026-02-19_dashboard_runbook.json"
        file_b = td / "2026-02-20_dashboard_runbook.json"
        file_c = td / "2026-02-21_dashboard_runbook.json"
        file_a.write_text(
            json.dumps({"run_date": "2026-02-21", "alerts": [], "steps": []}, ensure_ascii=False),
            encoding="utf-8",
        )
        file_b.write_text(
            json.dumps({"run_date": "2026-02-21", "alerts": [], "steps": []}, ensure_ascii=False),
            encoding="utf-8",
        )
        file_c.write_text(
            json.dumps({"run_date": "2026-02-20", "alerts": [], "steps": []}, ensure_ascii=False),
            encoding="utf-8",
        )
        os.utime(file_a, (1700000030, 1700000030))
        os.utime(file_b, (1700000090, 1700000090))
        os.utime(file_c, (1700000060, 1700000060))

        with patch("dashboard.api.main.REVIEW_DIR", str(td)):
            payload = list_dashboard_review_runbook_exports(
                request=None,
                limit=20,
                window_days=365,
                high_risk_top_n=3,
                visibility="internal",
            )
        data = payload.get("data", {}) if isinstance(payload.get("data", {}), dict) else {}
        items = data.get("items", []) if isinstance(data.get("items", []), list) else []
        self.assertEqual(len(items), 3)
        run_dates = [str((row if isinstance(row, dict) else {}).get("run_date", "")) for row in items]
        self.assertEqual(run_dates, ["2026-02-20", "2026-02-21", "2026-02-21"])
        modified_at_rows = [
            str((row if isinstance(row, dict) else {}).get("modified_at", ""))
            for row in items
        ]
        self.assertLessEqual(modified_at_rows[1], modified_at_rows[2])
        artifacts_rows = [
            ((row if isinstance(row, dict) else {}).get("artifacts", {}) or {})
            for row in items
        ]
        json_paths = [str((art if isinstance(art, dict) else {}).get("json_path", "")) for art in artifacts_rows]
        self.assertTrue(json_paths[0].endswith("2026-02-21_dashboard_runbook.json"))
        self.assertTrue(json_paths[1].endswith("2026-02-19_dashboard_runbook.json"))
        self.assertTrue(json_paths[2].endswith("2026-02-20_dashboard_runbook.json"))

