                if visibility == VISIBILITY_PUBLIC:
                    for limit in (0, 2):
                        latest = seen[(visibility, window_days, limit)][-1]
                        self.assertEqual(str(latest.get("latest_expected_action", "")), "")
                        self.assertTrue(
                            all(str(row[1]) == "" for row in latest.get("by_state", ())),
                            f"public redaction drift for window_days={window_days} limit={limit}",
                        )

