        self.assertEqual(set(forward_seen.keys()), set(expected.keys()))
        self.assertEqual(set(reversed_seen.keys()), set(expected.keys()))

        for key in expected:
            for signatures in (forward_seen[key], reversed_seen[key]):
                for signature in signatures[1:]:
                    self.assertEqual(signature, signatures[0], f"mirror direction drift for {key}")
                self.assertEqual(signatures[0], signatures[-1], f"mirror direction contamination for {key}")
            self.assertEqual(forward_seen[key][0], reversed_seen[key][0], f"mirror direction signature mismatch for {key}")

        for key in non_tail_keys:
            self.assertEqual(len(forward_seen[key]), 2)
            self.assertEqual(len(reversed_seen[key]), 2)

        self.assertEqual(len(forward_seen[relaxed_tail_key]), 6)
        self.assertEqual(len(forward_seen[strict_tail_key]), 5)
        self.assertEqual(len(reversed_seen[relaxed_tail_key]), 5)
        self.assertEqual(len(reversed_seen[strict_tail_key]), 6)

        for seen in (forward_seen, reversed_seen):
            for visibility in (VISIBILITY_OPS, VISIBILITY_PUBLIC):
                strict_w3 = seen[(visibility, 3, 0, 0)][-1]
                relaxed_w3 = seen[(visibility, 3, 2, 3)][-1]
                strict_w2 = seen[(visibility, 2, 0, 0)][-1]
                relaxed_w2 = seen[(visibility, 2, 2, 3)][-1]
                self.assertLessEqual(int(strict_w3.get("window_runs", 0)), int(relaxed_w3.get("window_runs", 0)))
                self.assertLessEqual(int(strict_w2.get("window_runs", 0)), int(relaxed_w2.get("window_runs", 0)))
                self.assertNotEqual(relaxed_w3, relaxed_w2)
                if visibility == VISIBILITY_PUBLIC:
                    for candidate in (strict_w3, relaxed_w3, strict_w2, relaxed_w2):
                        self.assertEqual(str(candidate.get("latest_expected_action", "")), "")
                        self.assertTrue(all(str(row[1]) == "" for row in candidate.get("by_state", ())))

