        self.assertEqual(len(forward_seen[key_strict_w2_ops]), 4)
        self.assertEqual(len(forward_seen[key_relaxed_w2_public]), 4)
        self.assertEqual(len(forward_seen[key_strict_w3_ops]), 4)
        self.assertEqual(len(reversed_seen[key_relaxed_w3_public]), 4)
        self.assertEqual(len(reversed_seen[key_strict_w2_ops]), 4)
        self.assertEqual(len(reversed_seen[key_relaxed_w2_public]), 3)
        self.assertEqual(len(reversed_seen[key_strict_w3_ops]), 4)

        for seen in (forward_seen, reversed_seen):
            for visibility in (VISIBILITY_OPS, VISIBILITY_PUBLIC):
                strict_w3 = seen[(visibility, 3, 0, 0)][-1]
                relaxed_w3 = seen[(visibility, 3, 2, 3)][-1]
                strict_w2 = seen[(visibility, 2, 0, 0)][-1]
