                self.assertLessEqual(int(strict_w2.get("window_runs", 0)), int(relaxed_w2.get("window_runs", 0)))
                self.assertNotEqual(relaxed_w3, relaxed_w2)
                if visibility == VISIBILITY_PUBLIC:
                    for candidate in (strict_w3, relaxed_w3, strict_w2, relaxed_w2):
                        self.assertEqual(str(candidate.get("latest_expected_action", "")), "")
                        self.assertTrue(all(str(row[1]) == "" for row in candidate.get("by_state", ())))

