    def test_record_and_get_runbook_triage_telemetry_summary(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        with patch("dashboard.api.main.LOGS_DIR", str(td)):
            record_dashboard_review_runbook_triage_telemetry(
                request=None,
                visibility="internal",
                payload={
                    "label": "playbook_bundle",
                    "outcome": "copied",
                    "run_date": "2026-02-21",
                    "risk_level": "high",
                    "risk_score": 8,
                    "playbook_profile": "frontend_route_audit_breach",
                    "command_preview": "set -euo pipefail",
                },
            )
            record_dashboard_review_runbook_triage_telemetry(
                request=None,
                visibility="internal",
                payload={
                    "label": "playbook_step_1",
                    "outcome": "copied",
                    "run_date": "2026-02-21",
                    "risk_level": "high",
                    "risk_score": 8,
                    "playbook_profile": "frontend_route_audit_breach",
                },
            )
            record_dashboard_review_runbook_triage_telemetry(
                request=None,
                visibility="internal",
                payload={
                    "label": "open_gate_report_command",
                    "outcome": "copy_failed",
                    "run_date": "2026-02-21",
                    "risk_level": "medium",
                    "risk_score": 5,
                    "playbook_profile": "high_risk_runbook_defect",
                },
            )
            summary_payload = get_dashboard_review_runbook_triage_telemetry(
                request=None,
                days=30,
                limit=10,
                visibility="internal",
            )
            ops_payload = get_dashboard_review_runbook_triage_telemetry(
                request=None,
                days=30,
                limit=10,
                visibility=VISIBILITY_OPS,
            )
            public_payload = get_dashboard_review_runbook_triage_telemetry(
                request=None,
                days=30,
                limit=10,
                visibility=VISIBILITY_PUBLIC,
            )

        data = summary_payload.get("data", {}) if isinstance(summary_payload.get("data", {}), dict) else {}
        self.assertEqual(int(data.get("window_events", 0)), 3)
        self.assertEqual(int(data.get("copy_success", 0)), 2)
        self.assertEqual(int(data.get("copy_failed", 0)), 1)
        self.assertEqual(int(data.get("bundle_copy_success", 0)), 1)
        self.assertEqual(int(data.get("step_copy_success", 0)), 1)
        self.assertAlmostEqual(float(data.get("copy_success_rate", 0.0)), 2.0 / 3.0, places=6)
        self.assertTrue(str(data.get("storage_path", "")).endswith("runbook_triage_telemetry.json"))
        self.assertGreaterEqual(int(data.get("prior_window_events", 0)), 0)
        heatmap = (
            data.get("label_outcome_heatmap", [])
            if isinstance(data.get("label_outcome_heatmap", []), list)
            else []
        )
        self.assertTrue(len(heatmap) >= 3)
        by_label = {
            str((row or {}).get("label", "")): row
            for row in heatmap
            if isinstance(row, dict)
        }
        bundle = by_label.get("playbook_bundle", {})
        self.assertEqual(int(bundle.get("total", 0)), 1)
        self.assertEqual(int(bundle.get("copied", 0)), 1)
        self.assertEqual(int(bundle.get("failed", 0)), 0)
        failed_row = by_label.get("open_gate_report_command", {})
        self.assertEqual(int(failed_row.get("total", 0)), 1)
        self.assertEqual(int(failed_row.get("copied", 0)), 0)
        self.assertEqual(int(failed_row.get("failed", 0)), 1)
        self.assertAlmostEqual(float(failed_row.get("success_rate", -1.0)), 0.0, places=6)
        drift_rows = (
            data.get("label_outcome_drift", [])
            if isinstance(data.get("label_outcome_drift", []), list)
            else []
        )
        if drift_rows:
            top_drift = drift_rows[0] if isinstance(drift_rows[0], dict) else {}
            self.assertIn(str(top_drift.get("severity", "")), {"low", "warn", "high"})
            self.assertTrue(str(top_drift.get("action_profile", "")).strip() != "")
        recent = data.get("recent_events", []) if isinstance(data.get("recent_events", []), list) else []
        self.assertTrue(len(recent) >= 3)
        latest = recent[0] if isinstance(recent[0], dict) else {}
        self.assertIn(str(latest.get("label", "")), {"playbook_bundle", "playbook_step_1", "open_gate_report_command"})
        daily_points = data.get("daily_points", []) if isinstance(data.get("daily_points", []), list) else []
        self.assertTrue(len(daily_points) >= 1)
        active_days = [row for row in daily_points if isinstance(row, dict) and int(row.get("events_total", 0) or 0) > 0]
        self.assertTrue(len(active_days) >= 1)
        self.assertAlmostEqual(float(active_days[-1].get("success_rate", 0.0)), 2.0 / 3.0, places=6)

        ops_data = ops_payload.get("data", {}) if isinstance(ops_payload.get("data", {}), dict) else {}
        ops_recent = ops_data.get("recent_events", []) if isinstance(ops_data.get("recent_events", []), list) else []
        ops_heatmap = (
            ops_data.get("label_outcome_heatmap", [])
            if isinstance(ops_data.get("label_outcome_heatmap", []), list)
            else []
        )
        ops_drift = (
            ops_data.get("label_outcome_drift", [])
            if isinstance(ops_data.get("label_outcome_drift", []), list)
            else []
        )
        self.assertTrue(len(ops_heatmap) >= 1)
        self.assertTrue(isinstance(ops_drift, list))
        if ops_recent:
            first = ops_recent[0] if isinstance(ops_recent[0], dict) else {}
            self.assertFalse("command_preview" in first)
        public_data = public_payload.get("data", {}) if isinstance(public_payload.get("data", {}), dict) else {}
        self.assertEqual(public_data.get("recent_events", []), [])
        self.assertEqual(public_data.get("top_labels", []), [])
        self.assertEqual(public_data.get("label_outcome_heatmap", []), [])
        self.assertEqual(public_data.get("label_outcome_drift", []), [])
        self.assertTrue(isinstance(public_data.get("daily_points", []), list))

    def test_get_runbook_triage_telemetry_label_outcome_drift_uses_prior_window(self) -> None:
        td = Path(tempfile.mkdtemp())
        self.addCleanup(lambda: shutil.rmtree(td, ignore_errors=True))
        now_utc = datetime.now(timezone.utc)
        current_ts = now_utc.isoformat(timespec="seconds").replace("+00:00", "Z")
        prior_ts = (now_utc - timedelta(days=8)).isoformat(timespec="seconds").replace("+00:00", "Z")
        payload = {
            "version": "v1",
            "updated_at": current_ts,
            "counters": {},
            "labels": {},
            "daily": {},
            "events": [
                {
                    "ts": current_ts,
                    "event_type": "copy",
                    "label": "drift_case",
                    "outcome": "copied",
                    "category": "quick_action",
                    "run_date": now_utc.date().isoformat(),
                    "risk_level": "low",
                    "risk_score": 1,
                    "playbook_profile": "monitoring",
                },
                {
                    "ts": prior_ts,
                    "event_type": "copy",
                    "label": "drift_case",
                    "outcome": "copy_failed",
                    "category": "quick_action",
                    "run_date": (now_utc - timedelta(days=8)).date().isoformat(),
                    "risk_level": "low",
                    "risk_score": 1,
                    "playbook_profile": "monitoring",
                },
            ],
        }
        path = td / "runbook_triage_telemetry.json"
        path.write_text(json.dumps(payload, ensure_ascii=False), encoding="utf-8")
        with patch("dashboard.api.main.LOGS_DIR", str(td)):
            response = get_dashboard_review_runbook_triage_telemetry(
                request=None,
                days=7,
                limit=10,
                visibility="internal",
            )
        data = response.get("data", {}) if isinstance(response.get("data", {}), dict) else {}
        self.assertEqual(int(data.get("window_events", 0)), 1)
        self.assertEqual(int(data.get("prior_window_events", 0)), 1)
        drift_rows = (
            data.get("label_outcome_drift", [])
            if isinstance(data.get("label_outcome_drift", []), list)
            else []
        )
        self.assertTrue(len(drift_rows) >= 1)
        first = drift_rows[0] if isinstance(drift_rows[0], dict) else {}
        self.assertEqual(str(first.get("label", "")), "drift_case")
        self.assertEqual(int(first.get("current_total", 0)), 1)
        self.assertEqual(int(first.get("prior_total", 0)), 1)
        self.assertAlmostEqual(float(first.get("copied_rate_delta", 0.0)), 1.0, places=6)
        self.assertAlmostEqual(float(first.get("failed_rate_delta", 0.0)), -1.0, places=6)
        self.assertAlmostEqual(float(first.get("drift_score", 0.0)), 1.0, places=6)
        self.assertIn(str(first.get("severity", "")), {"warn", "high"})
        self.assertTrue(str(first.get("action_profile", "")).strip() != "")
        self.assertIn("--date", str(first.get("recommended_command", "")))

