    def test_get_dashboard_ops_latest_dependency_audit_artifact_trend_maps_next_actions_by_state(self) -> None:
        gate_payload = {
            "date": "2026-02-21",
            "passed": True,
            "checks": {
                "mode_drift_ok": True,
                "style_drift_ok": True,
                "state_stability_ok": True,
                "trendline_controlled_apply_ledger_drift_ok": True,
                "trendline_controlled_apply_ledger_artifact_ok": True,
            },
        }
        store_info = {
            "backend": "postgres",
            "requested_backend": "postgres",
            "degraded": False,
            "fallback": False,
        }

        def _build_ops_payload(status: str, checks: dict, alerts: list[str]) -> dict:
            return {
                "status": "ok",
                "date": "2026-02-21",
                "dependency_audit": {
                    "active": True,
                    "gate_ok": True,
                    "artifact_corrupt": False,
                    "source_exists": True,
                    "alerts": [],
                    "checks": {
                        "dependency_ok": True,
                        "dashboard_adapter_ok": True,
                        "artifact_ok": True,
                    },
                },
                "dependency_audit_artifact_trend": {
                    "active": True,
                    "gate_ok": False,
                    "status": status,
                    "alerts": alerts,
                    "checks": checks,
                    "metrics": {
                        "corrupt_ratio": 0.35,
                        "missing_ratio": 0.25,
                        "source_age_days": 4,
                    },
                },
            }

        cases = [
            (
                "stale",
                {
                    "min_samples_ok": True,
                    "artifact_recent_ok": False,
                    "corrupt_ratio_ok": True,
                    "missing_ratio_ok": True,
                },
                ["dependency_audit_artifact_trend_stale"],
                "rerun_dependency_audit_for_artifact_freshness",
            ),
            (
                "missing_ratio_high",
                {
                    "min_samples_ok": True,
                    "artifact_recent_ok": True,
                    "corrupt_ratio_ok": True,
                    "missing_ratio_ok": False,
                },
                ["dependency_audit_artifact_trend_missing_ratio_high"],
                "backfill_dependency_audit_artifacts_and_scheduler",
            ),
        ]

        for status, checks, alerts, expected_action in cases:
            ops_payload = _build_ops_payload(status, checks, alerts)

            def _find_latest_file(pattern: str) -> str:
                if "gate_report" in pattern:
                    return "/tmp/fake_gate_report.json"
                if "ops_report" in pattern:
                    return "/tmp/fake_ops_report.json"
                return ""

            def _load_json_file(path: str) -> dict:
                if path.endswith("fake_gate_report.json"):
                    return gate_payload
                if path.endswith("fake_ops_report.json"):
                    return ops_payload
                return {}

            with patch("dashboard.api.main._resolve_workflow_store", return_value=(self._fake_store(), store_info)):
                with patch("dashboard.api.main.find_latest_file", side_effect=_find_latest_file):
                    with patch("dashboard.api.main.load_json_file", side_effect=_load_json_file):
                        payload = get_dashboard_ops_latest(request=None, visibility=VISIBILITY_OPS)

            data = payload.get("data", {}) if isinstance(payload.get("data", {}), dict) else {}
            hints = data.get("defect_hints", []) if isinstance(data.get("defect_hints", []), list) else []
            matched = [
                item
                for item in hints
                if isinstance(item, dict)
                and str(item.get("code", "")).strip().upper() == "DEPENDENCY_AUDIT_ARTIFACT_TREND_FAILED"
            ]
            self.assertTrue(bool(matched))
            self.assertEqual(str(matched[0].get("next_action", "")), expected_action)

    def test_get_dashboard_ops_dependency_audit_artifact_trend_drilldown_7d_30d(self) -> None:
        with tempfile.TemporaryDirectory() as td:
            base = Path(td)
            rows = [
                (
                    "2026-02-20",
                    "ok",
                    True,
                    {
                        "min_samples_ok": True,
                        "artifact_recent_ok": True,
                        "corrupt_ratio_ok": True,
                        "missing_ratio_ok": True,
                    },
                    [],
                ),
                (
                    "2026-02-21",
                    "stale",
                    False,
                    {
                        "min_samples_ok": True,
                        "artifact_recent_ok": False,
                        "corrupt_ratio_ok": True,
                        "missing_ratio_ok": True,
                    },
                    ["dependency_audit_artifact_trend_stale"],
                ),
                (
                    "2026-02-22",
                    "corrupt_ratio_high",
                    False,
                    {
                        "min_samples_ok": True,
                        "artifact_recent_ok": True,
                        "corrupt_ratio_ok": False,
                        "missing_ratio_ok": True,
                    },
                    ["dependency_audit_artifact_trend_corrupt_ratio_high"],
                ),
                (
                    "2026-02-23",
                    "missing_ratio_high",
                    False,
                    {
                        "min_samples_ok": True,
                        "artifact_recent_ok": True,
                        "corrupt_ratio_ok": True,
                        "missing_ratio_ok": False,
                    },
                    ["dependency_audit_artifact_trend_missing_ratio_high"],
                ),
            ]
            for run_date, status, gate_ok, checks, alerts in rows:
                payload = {
                    "date": run_date,
                    "dependency_audit_artifact_trend": {
                        "active": True,
                        "gate_ok": gate_ok,
                        "status": status,
                        "window_days": 14,
                        "samples": 10,
                        "checks": checks,
                        "alerts": alerts,
                        "metrics": {
                            "corrupt_ratio": 0.4 if status == "corrupt_ratio_high" else 0.0,
                            "missing_ratio": 0.5 if status == "missing_ratio_high" else 0.0,
                            "source_age_days": 5 if status == "stale" else 0,
                        },
                    },
                }
                (base / f"{run_date}_ops_report.json").write_text(
                    json.dumps(payload, ensure_ascii=False),
                    encoding="utf-8",
                )

            with patch("dashboard.api.main.REVIEW_DIR", str(base)):
                payload_7 = get_dashboard_ops_dependency_audit_artifact_trend(
                    request=None,
                    visibility=VISIBILITY_OPS,
                    window_days=7,
                )
                payload_30 = get_dashboard_ops_dependency_audit_artifact_trend(
                    request=None,
                    visibility=VISIBILITY_OPS,
                    window_days=30,
                )

            data_7 = payload_7.get("data", {}) if isinstance(payload_7.get("data", {}), dict) else {}
